package com.nstut.buildinggadgetsextra.client;import com.mojang.blaze3d.matrix.MatrixStack;import com.nstut.buildinggadgetsextra.common.ExtraConstants;import net.minecraft.client.gui.screen.Screen;import net.minecraft.client.gui.widget.button.Button;import net.minecraft.util.text.TranslationTextComponent;
public final class StructureLibraryScreen extends Screen{private final Screen parent;public StructureLibraryScreen(Screen parent){super(new TranslationTextComponent(ExtraConstants.STRUCTURE_LIBRARY));this.parent=parent;}@Override protected void init(){int left=width/2-100,top=height/2-10;addButton(new Button(left,top,98,20,new TranslationTextComponent(ExtraConstants.SAVE_STRUCTURE),b->ClientStructureFiles.chooseSave()));addButton(new Button(left+102,top,98,20,new TranslationTextComponent(ExtraConstants.LOAD_STRUCTURE),b->ClientStructureFiles.chooseLoad()));}@Override public void render(MatrixStack s,int x,int y,float p){renderBackground(s);drawCenteredString(s,font,title,width/2,height/2-35,0xFFFFFFFF);super.render(s,x,y,p);}@Override public void onClose(){minecraft.setScreen(parent);}}
